import { createContext } from 'react';

import { createStore, type Store } from '@dynatrace/strato-components/core';

import type { MapState } from '../types/state.js';

const initialSelection = { highlightedSeries: undefined, visible: undefined };

export const initialState: MapState = {
  tooltip: {
    enabled: true,
    hoveredLayerId: undefined,
    location: undefined,
  },
  overlay: {
    mouseInBounds: false,
  },
  selection: initialSelection,
  zoom: {
    zoomInEnabled: true,
    zoomOutEnabled: true,
    zoomToFitEnabled: true,
    resetEnabled: false,
  },
};

export const MapStore = createContext<Store<MapState>>(
  createStore<MapState>(initialState),
);

MapStore['displayName'] = 'MapStore';
